// ── Validate required fields ────────────────────────────────────────────────
const body = $input.first().json.body || $input.first().json;

const required = ['staffName', 'dateApplied', 'oilDate', 'oilHours', 'reason'];
for (const field of required) {
  if (!body[field] || body[field].toString().trim() === '') {
    throw new Error(`Missing required field: ${field}`);
  }
}

const hours = parseFloat(body.oilHours);
if (isNaN(hours) || hours <= 0 || hours > 24) {
  throw new Error('OIL hours must be a number between 0.5 and 24.');
}

// If partial day (< 10 hours), From/To times are required
if (hours < 10) {
  if (!body.oilTimeFrom || !body.oilTimeTo) {
    throw new Error('OIL From Time and To Time are required for partial day claims (less than 10 hours).');
  }
}

// Build clean record
const staffName    = body.staffName.trim();
const dateApplied  = body.dateApplied;
const oilDate      = body.oilDate;
const oilHours     = hours;
const oilTimeFrom  = hours >= 10 ? 'Full Day' : (body.oilTimeFrom || '');
const oilTimeTo    = hours >= 10 ? 'Full Day' : (body.oilTimeTo   || '');
const reason       = body.reason.trim();
const submittedAt  = new Date().toISOString();

return [{
  json: {
    staffName,
    dateApplied,
    oilDate,
    oilHours,
    oilTimeFrom,
    oilTimeTo,
    reason,
    submittedAt,
    validationStatus: 'Pending'
  },
  binary: $input.first().binary
}];

// ── Validate uploaded file ───────────────────────────────────────────────────
const binary = $input.first().binary;

if (!binary || !binary.approvalFile) {
  throw new Error('Approval file is missing from the submission.');
}

const file     = binary.approvalFile;
const mimeType = file.mimeType || '';
const allowed  = ['image/jpeg', 'image/png', 'image/gif', 'image/webp', 'application/pdf'];

if (!allowed.includes(mimeType)) {
  throw new Error(`Invalid file type: ${mimeType}. Only JPG, PNG, GIF, WEBP, or PDF files are accepted.`);
}

const ext = mimeType === 'application/pdf' ? 'pdf'
  : mimeType === 'image/png'  ? 'png'
  : mimeType === 'image/gif'  ? 'gif'
  : mimeType === 'image/webp' ? 'webp'
  : 'jpg';

// Build Drive filename: StaffName_DateApplied_OILHours_Approval.ext
const data = $input.first().json;
const safeName      = data.staffName.replace(/[^a-zA-Z0-9]/g, '_');
const safeDate      = data.dateApplied.replace(/-/g, '-');
const safeHours     = data.oilHours.toString().replace('.', 'p');
const driveFileName = `${safeName}_${safeDate}_${safeHours}h_Approval.${ext}`;
const monthFolder   = data.dateApplied.substring(0, 7);

return [{
  json: { ...data, driveFileName, monthFolder, fileExt: ext },
  binary
}];

// ── Extract Drive file link from upload response ─────────────────────────────
const driveData = $input.first().json;

const fileId   = driveData.id || driveData.fileId || '';
const fileLink = driveData.webViewLink
  || (fileId ? `https://drive.google.com/file/d/${fileId}/view` : 'N/A');

const prevData = $('Validate File Type & Name').first().json;

return [{
  json: {
    ...prevData,
    driveFileId: fileId,
    approvalFileLink: fileLink
  }
}];
